import { PackFlags, UIBase } from "../core/ui_base";
import { ColumnFrame } from "../core/ui";
import { ListProperty, PropFlags, StringSetProperty } from "../path-controller/toolsys/toolprop";
import { UndoFlags, ToolFlags, ToolOp } from "../path-controller/toolsys/toolsys";

import { ToolProperty } from "../path-controller/toolsys/toolprop";
import { IContextBase } from "../core/context_base";

const LastKey = Symbol("LastToolPanelId");
let tool_idgen = 0;

export function getLastToolStruct(ctx: IContextBase) {
  let ret = (ctx.state as any)._last_tool;

  if (!ret) {
    ret = ctx.toolstack.head;
  } else {
    let msg = "Passing the last tool to last-tool-panel via appstate._last_tool is deprecated;";
    msg += "\nctx.toolstack.head is now used instead.";

    console.warn(msg);
  }

  return ret;
}

interface ToolEventEntry {
  panel: LastToolPanel;
  cb: (() => void) | null;
  prop: ToolProperty;
}

const last_tool_eventmap: ToolEventEntry[] = [];

/* Try to avoid memory leaks when last tool panels are hidden. */
window.setInterval(() => {
  for (const entry of last_tool_eventmap) {
    const panel = entry.panel;
    if (!panel.isConnected || panel.hidden) {
      if (window.DEBUG && (window.DEBUG as any).lastToolPanel) {
        console.log("Disconnecting last tool panel from toolstack.");
      }

      panel.unlinkEvents();
      panel.needsRebuild = true;
      break;
    }
  }
}, 500);

/*
 *
 * This panel shows the most recently executed ToolOp's
 * settings.  It assumes that recent toolops are accessible
 * in ctx.last_tool.
 * */
export class LastToolPanel<CTX extends IContextBase = IContextBase> extends ColumnFrame<CTX> {
  ignoreOnChange: boolean;
  on_change: (() => void) | null;
  _tool_id: number | undefined;
  needsRebuild: boolean;
  last_tool: ToolOp | undefined;

  constructor() {
    super();

    this.ignoreOnChange = false;
    this.on_change = null;
    this._tool_id = undefined;
    this.useDataPathUndo = false;
    this.needsRebuild = false;
  }

  init() {
    super.init();

    this.useDataPathUndo = false;
    this.rebuild();
  }

  /** client code can subclass and override this method */
  getToolStackHead(ctx: CTX) {
    //don't process the root toolop
    let bad: boolean = ctx.toolstack.length === 0 || ctx.toolstack.cur >= ctx.toolstack.length;
    bad = bad || ctx.toolstack.cur < 0;
    bad = bad || !!(ctx.toolstack[ctx.toolstack.cur].undoflag & UndoFlags.IS_UNDO_ROOT);

    if (bad) {
      return undefined;
    }

    return ctx.toolstack[ctx.toolstack.cur];
  }

  rebuild() {
    const ctx = this.ctx;
    if (ctx === undefined) {
      this._tool_id = -1; //wait for .ctx
      return;
    }

    this.needsRebuild = false;

    this.clear();

    this.label("Recent Command Settings");

    const tool = this.getToolStackHead(ctx);

    if (!tool) {
      this.setCSS();
      return;
    }

    const def = (tool.constructor as any).tooldef();
    const name = def.uiname !== undefined ? def.uiname : def.name;

    const panel = this.panel(def.uiname);

    this.on_change = () => {
      if (this.ignoreOnChange) {
        return;
      }

      if (tool.modalRunning) {
        return;
      }

      if (tool === ctx.toolstack.head) {
        this.ignoreOnChange = true;
        ctx.toolstack.rerun(tool);
        this.ignoreOnChange = false;
      } else {
        this.unlinkEvents();
      }
    };

    this.buildTool(ctx, tool, panel);
    this.flushUpdate();
    this.flushUpdate();
  }

  unlinkEvents() {
    for (const entry of Array.from(last_tool_eventmap)) {
      if (entry.panel === (this as any) || !entry.panel.isConnected) {
        entry.prop.off("change", entry.cb!);
        (last_tool_eventmap as any).remove(entry);

        if (entry.panel !== (this as any)) {
          entry.panel.needsRebuild = true;
        }
      }
    }
  }

  /** client code can subclass and override this method */
  buildTool(ctx: CTX, tool: ToolOp, panel: any) {
    if (tool.flag & ToolFlags.PRIVATE) {
      return;
    }

    this.unlinkEvents();
    this.last_tool = tool;

    panel.useDataPathUndo = false;
    for (const k in tool.inputs) {
      const prop = (tool.inputs as any)[k] as ToolProperty;

      // do not do list properties
      if (prop instanceof ListProperty || prop instanceof StringSetProperty) {
        continue;
      }

      if (prop.flag & (PropFlags.PRIVATE | PropFlags.READ_ONLY)) {
        continue;
      }

      prop.on("change", this.on_change!);
      last_tool_eventmap.push({
        panel: this as any,
        cb   : this.on_change,
        prop,
      });

      const path = `last_tool.${k}`;
      const uiname = prop.uiname ?? ToolProperty.makeUIName(k);

      panel.label(uiname);
      let packflag = 0;

      /* Default to roller number sliders. */
      if (!(prop.flag & PropFlags.SIMPLE_SLIDER)) {
        packflag |= PackFlags.FORCE_ROLLER_SLIDER;
      }

      const ret = panel.prop(path, packflag);

      if (ret) {
        //ret.onchange = function() {
        //ctx.toolstack.rerun(tool);
        //}
      }
    }
    this.setCSS();
  }

  update() {
    super.update();
    const ctx = this.ctx;

    if (!ctx) {
      return;
    }

    const tool = this.getToolStackHead(ctx) as any;

    this.needsRebuild = this.needsRebuild || (tool && (!(LastKey in tool) || tool[LastKey] !== this._tool_id));

    if (this.needsRebuild) {
      tool[LastKey] = tool_idgen++;
      this._tool_id = tool[LastKey];

      this.rebuild();
    }
  }

  static define() {
    return {
      tagname: "last-tool-panel-x",
    };
  }
}

UIBase.internalRegister(LastToolPanel);
